import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, } from '@angular/core';
/**
 * Navigation principale horizontale.
 * `<nav aria-label>` + `<ul>` + `aria-current="page"` sur l'item actif.
 */
let PfMainNavigationComponent = class PfMainNavigationComponent {
    constructor() {
        this.items = [];
        this.ariaLabel = 'Navigation principale';
    }
    static { this.propDecorators = {
        items: [{ type: Input }],
        ariaLabel: [{ type: Input }]
    }; }
};
PfMainNavigationComponent = __decorate([
    Component({
        selector: 'pf-main-navigation',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <nav [attr.aria-label]="ariaLabel">
      <ul class="ds-main-nav">
        @for (item of items; track item.href) {
          <li class="ds-main-nav__item">
            <a
              [href]="item.href"
              class="ds-main-nav__link"
              [attr.aria-current]="item.current ? 'page' : null"
            >{{ item.label }}</a>
          </li>
        }
      </ul>
    </nav>
  `,
    })
], PfMainNavigationComponent);
export { PfMainNavigationComponent };
